# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['content_management']
users_collection = db['users']
documents_collection = db['documents']

# User profile storage
@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.json
    users_collection.insert_one(user_data)
    return jsonify({'message': 'User created successfully'}), 201

# Document queries
@app.route('/documents', methods=['GET'])
def get_documents():
    query = request.args.get('query')
    documents = documents_collection.find({'title': {'$regex': query}})
    return jsonify(list(documents)), 200

# Aggregation pipelines
@app.route('/analytics', methods=['GET'])
def get_analytics():
    pipeline = [
        {'$match': {'category': 'news'}},
        {'$group': {'_id': '$author', 'count': {'$sum': 1}}},
        {'$sort': {'count': -1}}
    ]
    results = documents_collection.aggregate(pipeline)
    return jsonify(list(results)), 200

if __name__ == '__main__':
    app.run(debug=True)